<?phpfunction sql_connect($host, $dbname, $dbuser, $dbpsd){    $GLOBALS['curConn'] = mysql_pconnect($host, $dbuser, $dbpsd);    if(!$GLOBALS['curConn'])    {        throw new Exception(mysql_errno() . ": " . mysql_error());    }    mysql_set_charset('utf8', $GLOBALS['curConn']);    mysql_select_db($dbname, $GLOBALS['curConn']);}function sql_query($sql){    if(!$GLOBALS['curConn'])    {        //sql_connect();        exit('请先连接数据库');    }    $r = mysql_query($sql,$GLOBALS['curConn']);    if($r == false)    {        $errno=mysql_error($GLOBALS['curConn']);        if($errno == 2006)        {            //sql_connect();            exit('请先连接数据库');            $r = mysql_query($sql,$GLOBALS['curConn']);            if($r == false)            {                throw new Exception(mysql_errno($GLOBALS['curConn']) . ": " . mysql_error($GLOBALS['curConn']));            }        }        else        {            throw new Exception(mysql_errno($GLOBALS['curConn']) . ": " . $errno);        }    }    return $r;}function sql_fetch_one($sql){    $r = sql_query($sql);    if(mysql_num_rows($r) == 0)    {        mysql_free_result($r);        return "";    }    if ((!empty($r))&&($row = mysql_fetch_array($r, MYSQL_ASSOC)))    {        mysql_free_result($r);        return $row;    }    return mysql_error();}function sql_fetch_one_cell($sql){    $r = sql_query($sql);        if ((!empty($r))&&($row = mysql_fetch_array($r, MYSQL_NUM)))    {        mysql_free_result($r);        return $row[0];    }    else    {        mysql_free_result($r);        return false;    }    return 0;}function sql_fetch_rows($sql){    $r = sql_query($sql);        $ret = array();    while($row = mysql_fetch_array($r,MYSQL_ASSOC))    {        $ret[] = $row;    }        mysql_free_result($r);    return $ret;}function sql_insert($sql){    sql_query($sql);        return sql_fetch_one_cell('select last_insert_id()');}function sql_fetch_object($table, $id, $idname="id"){    return sql_fetch_one("SELECT * FROM `$table` WHERE `$idname`=$id");}function sql_insert_object($table, $obj){    if(!$obj)    {        return 0;    }        $sql = "INSERT INTO `$table` ";    $keys = "(";    $values = "(";    $r = "";    foreach ($obj as $key=>$value)    {        $keys .= ( $r . "`".$key."`");        $values .= ( $r . "'" . $value . "'");        $r = ",";    }    $keys .= ")";    $values .= ")";    $sql = $sql . $keys . " VALUES " . $values;    return sql_insert($sql);}function sql_replace_object($table, $obj){    if(!$obj)    {        return 0;    }        $sql = "REPLACE INTO $table ";    $keys = "(";    $values = "(";    $r = "";    foreach ($obj as $key=>$value)    {        $keys .= ( $r . "`" . $key . "`");        $values .= ( $r . "'" . $value . "'");        $r = ",";    }    $keys .= ")";    $values .= ")";    $sql = $sql . $keys . " VALUES " . $values;    return sql_insert($sql);}function sql_replace_objects($table, $objs){    if($objs) foreach($objs as $key=>$value)    {        sql_replace_object($table, $value);    }}function sql_check($sql){    $r = sql_query($sql);        if (empty($r))    {        return false;    }        if (mysql_num_rows($r) > 0)    {        return true;    }    else    {        return false;    }}function get_client_ip(){    if (isset($_SERVER['HTTP_X_FORWARDED_FOR']))    {        $ip = $_SERVER['HTTP_X_FORWARDED_FOR'];    }    elseif (isset($_SERVER['REMOTE_ADDR']))    {        $ip = $_SERVER['REMOTE_ADDR'];    }    else    {        $ip = '0.0.0.0' ;    }    return $ip;}?>